#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
BILNOV — Lot CAO+ : accrochage OSNAP, outil superficie (polygone multi-points),
et detection automatique de l unite du dessin ($INSUNITS) avec conversion.
A deposer a la racine du repo (bilnov-app) puis : python3 apply_cad_snap_area.py
"""
import base64, os

FILES = {
  'src/lib/cad.ts': "",
  'src/lib/snap.ts': "",
  'src/components/CadViewer.tsx': "",
  'public/cad/dwg-worker.js': "",
}

def main():
    for rel, b64 in FILES.items():
        data = base64.b64decode(b64)
        d = os.path.dirname(rel)
        if d and not os.path.isdir(d): os.makedirs(d, exist_ok=True)
        with open(rel, "wb") as f: f.write(data)
        print("ecrit", rel)
    print()
    print("=== Lot CAO+ applique (OSNAP + superficie multi-points + unite auto). ===")
    print("git add -A && git commit -m \"feat(cad): OSNAP + superficie + unite auto\" && git push origin main")

if __name__ == "__main__": main()
